// scripts/apply-song-displays-migration.mjs
// Applies drizzle/0006_song_displays.sql to Supabase via postgres-js.
//
// Why a custom apply script instead of `drizzle-kit migrate`?
//   - The journal/snapshot pair under drizzle/meta/ is regenerated by
//     `pnpm drizzle-kit generate`, which compares the live schema.ts
//     against the latest snapshot. Running it here would also include
//     any other unrelated schema drift, which we explicitly want to avoid.
//   - This script applies ONLY the song_displays migration in a single
//     transaction. Idempotent via IF NOT EXISTS guards.
//
// Usage:
//   node scripts/apply-song-displays-migration.mjs --dry-run
//   node scripts/apply-song-displays-migration.mjs

import postgres from "postgres";
import dotenv from "dotenv";

dotenv.config();

const DB_URL =
  process.env.SUPABASE_SESSION_POOLER_STRING ??
  process.env.SUPABASE_DIRECT_CONNECTION_STRING ??
  process.env.DATABASE_URL;
if (!DB_URL) {
  console.error("Set SUPABASE_SESSION_POOLER_STRING in .env");
  process.exit(1);
}

const DRY_RUN = process.argv.includes("--dry-run") || process.argv.includes("--dry");

const STATEMENTS = [
  `CREATE TABLE IF NOT EXISTS "song_displays" (
     "id" serial PRIMARY KEY NOT NULL,
     "songId" integer NOT NULL,
     "userId" integer,
     "guestToken" varchar(64),
     "roomCode" varchar(8),
     "variantIndex" integer DEFAULT 0 NOT NULL,
     "shownAt" timestamp with time zone DEFAULT now() NOT NULL
   )`,
  `ALTER TABLE "songs" ADD COLUMN IF NOT EXISTS "displayCount" integer DEFAULT 0 NOT NULL`,
  `ALTER TABLE "songs" ADD COLUMN IF NOT EXISTS "lastShownAt" timestamp with time zone`,
  `CREATE INDEX IF NOT EXISTS "song_displays_user_shown_at_idx"
     ON "song_displays" USING btree ("userId","shownAt")`,
  `CREATE INDEX IF NOT EXISTS "song_displays_guest_shown_at_idx"
     ON "song_displays" USING btree ("guestToken","shownAt")`,
  `CREATE INDEX IF NOT EXISTS "song_displays_song_id_idx"
     ON "song_displays" USING btree ("songId")`,
];

if (DRY_RUN) {
  console.log("Dry-run. Statements that would execute:");
  for (const s of STATEMENTS) {
    console.log("  " + s.replace(/\s+/g, " ").trim());
  }
  process.exit(0);
}

const sql = postgres(DB_URL, { max: 2 });

try {
  console.log("Applying song_displays migration in a single transaction ...");
  await sql.begin(async (tx) => {
    for (const s of STATEMENTS) {
      await tx.unsafe(s);
    }
  });
  console.log("Migration applied.");
} catch (err) {
  console.error("Migration failed:", err.message);
  process.exitCode = 1;
} finally {
  await sql.end();
}
